+import { $internal } from '../../common';
+import type { Entity } from '../../entity/types';
+import type { Relation } from '../../relation/types';
+import type { Trait } from '../../trait/types';
+import type { World } from '../../world';
+import { checkQueryTracking } from '../utils/check-query-tracking';
+
+/** Record and dispatch a target-specific relation event. */
+export function setPairTrackingEvent(
+    world: World,
+    entity: Entity,
+    relation: Relation<Trait>,
+    target: Entity,
+    eventType: 'add' | 'remove' | 'change'
+) {
+    const ctx = world[$internal];
+    const relationTrait = relation[$internal].trait;
+    const instance = ctx.traitInstances[relationTrait.id];
+    if (!instance) return;
+    const key = `${relationTrait.id}:${entity.id()}:${target}`;
+
+    for (const [factoryId, events] of ctx.pairTracking) {
+        const previous = events.get(key);
+        if ((previous === 'add' && eventType === 'remove') || (previous === 'remove' && eventType === 'add')) {
+            events.delete(key);
+        } else {
+            events.set(key, eventType);
+        }
+
+        for (const query of instance.trackingQueries) {
+            for (const group of query.trackingGroups) {
+                if (group.id !== factoryId || group.type !== eventType) continue;
+                for (let index = 0; index < group.relationPairs.length; index++) {
+                    const pairCtx = group.relationPairs[index][$internal];
+                    if (
+                        pairCtx.relation !== relation ||
+                        (pairCtx.target !== '*' && pairCtx.target !== target)
+                    ) continue;
+                    let tracked = group.pairTrackers.get(entity.id());
+                    if (!tracked) group.pairTrackers.set(entity.id(), (tracked = new Set()));
+                    if (events.get(key) === eventType) tracked.add(index);
+                    else tracked.delete(index);
+                }
+            }
+            const match = checkQueryTracking(world, query, entity, eventType, -1, 0);
+            if (match) query.add(entity);
+            else query.remove(world, entity);
+        }
+    }
+}
